parameters.jsCode:
// ============================================================
// Parse Groq Response — production-safe classification parser
// ============================================================
// Reads the upstream Groq HTTP response, extracts category +
// urgency, validates them, and ALWAYS returns clean output.
// On ANY failure it defaults to General / Low so the workflow
// never breaks a ticket.
// ============================================================

const VALID_CATEGORIES = ['Urgent', 'Billing', 'General'];
const VALID_URGENCIES = ['High', 'Medium', 'Low'];

// Pull the original email fields forwarded from "Extract Email Fields".
const email = $('Extract Email Fields').item.json;

// Defaults — used whenever anything goes wrong.
let category = 'General';
let urgency = 'Low';
let parseStatus = 'ok';

try {
  const resp = $input.item.json;

  // 1) Detect upstream HTTP / network errors (neverError surfaced them here).
  if (resp.error || resp.code || resp.message) {
    throw new Error('Groq API error: ' + JSON.stringify(resp.error || resp.message || resp.code));
  }

  // 2) Locate the model's text output (OpenAI-compatible shape).
  const raw = resp?.choices?.[0]?.message?.content;
  if (!raw || typeof raw !== 'string') {
    throw new Error('Missing choices[0].message.content in Groq response');
  }

  // 3) Strip any accidental code fences, then isolate the JSON object.
  const cleaned = raw.replace(/```json/gi, '').replace(/```/g, '').trim();
  const match = cleaned.match(/\{[\s\S]*\}/);
  if (!match) {
    throw new Error('No JSON object found in model output: ' + cleaned.slice(0, 120));
  }

  // 4) Parse safely.
  const parsed = JSON.parse(match[0]);

  // 5) Validate fields; fall back to defaults if invalid.
  if (VALID_CATEGORIES.includes(parsed.category)) {
    category = parsed.category;
  } else {
    parseStatus = 'invalid_category';
  }
  if (VALID_URGENCIES.includes(parsed.urgency)) {
    urgency = parsed.urgency;
  } else {
    parseStatus = 'invalid_urgency';
  }

  console.log('[Groq parse] OK ->', { category, urgency, ticketRef: email.ticketRef });
} catch (err) {
  // Any failure: log it, keep safe defaults.
  parseStatus = 'fallback';
  console.error('[Groq parse] FAILED, defaulting to General/Low ->', err.message);
}

// 6) Return one clean item with everything downstream nodes need.
return [
  {
    json: {
      category,
      urgency,
      parseStatus,
      emailSubject: email.emailSubject || 'No Subject',
      emailBody: email.emailBody || '',
      sender: email.sender || 'unknown@unknown.com',
      receivedDate: email.receivedDate || new Date().toISOString(),
      ticketRef: email.ticketRef || ('TKT-' + Date.now()),
      messageId: email.messageId || '',
      classifiedAt: new Date().toISOString()
    }
  }
];

// ============================================================
// Build Slack Blocks — constructs Slack Block Kit JSON as a
// real JS object and serializes with JSON.stringify, instead of
// hand-writing JSON-with-expressions (which breaks on \n inside
// mrkdwn text: n8n resolves {{ }} via template literals, turning
// literal \n into raw newline bytes that JSON.parse rejects).
// ============================================================

const j = $input.item.json;

const blocks = {
  blocks: [
    { type: 'header', text: { type: 'plain_text', text: '🚨 Urgent Support Ticket', emoji: true } },
    { type: 'section', fields: [
      { type: 'mrkdwn', text: `*Ticket:*\n${j.ticketRef}` },
      { type: 'mrkdwn', text: `*Urgency:*\n${j.urgency}` },
      { type: 'mrkdwn', text: `*From:*\n${j.sender}` },
      { type: 'mrkdwn', text: `*Received:*\n${j.receivedDate}` }
    ] },
    { type: 'section', text: { type: 'mrkdwn', text: `*Subject:* ${j.emailSubject}` } },
    { type: 'context', elements: [ { type: 'mrkdwn', text: 'Auto-routed by AI Support Router • category=Urgent' } ] }
  ]
};

return [
  {
    json: {
      ...j,
      slackBlocksJson: JSON.stringify(blocks)
    }
  }
];

