// ============================================================
// Build Templates — generates HTML email bodies + merges all
// three Switch branches back into a single stream for the
// universal confirmation email + logging.
// ============================================================
// The Switch sends each item down ONE branch; we connect all
// branches here so every ticket (Urgent/Billing/General) gets
// a confirmation email and a Sheets log row.
//
// Templates mirror the static files in /templates/*.html so the
// design stays in sync if you edit either copy.
// ============================================================

const COMPANY = $env.COMPANY_NAME || 'Our Support Team';
const FAQ_LINK = $env.FAQ_LINK || 'https://example.com/faq';
const out = [];

for (const item of $input.all()) {
  const j = item.json;
  const ref = j.ticketRef || ('TKT-' + Date.now());
  const subject = j.emailSubject || 'your request';

  // ---- Universal confirmation email (sent to ALL categories) ----
  const confirmationHtml = `
  <div style="font-family:Arial,sans-serif;color:#1a1a1a;line-height:1.6">
    <h2 style="color:#2563eb;margin:0 0 8px">${COMPANY}</h2>
    <p>Hi there,</p>
    <p>We've received your message regarding "<strong>${subject}</strong>" and created a support ticket.</p>
    <p style="background:#f1f5f9;padding:10px 14px;border-radius:6px">
      <strong>Ticket Reference:</strong> ${ref}<br/>
      <strong>Category:</strong> ${j.category}<br/>
      <strong>Priority:</strong> ${j.urgency}
    </p>
    <p>Our team will follow up shortly. Please keep this reference for any replies.</p>
    <p>Warm regards,<br/>${COMPANY}</p>
  </div>`;

  // ---- Urgent-only escalation reply (mirrors templates/email-urgent.html) ----
  const urgentReplyHtml = `
  <div style="font-family:Arial,sans-serif;color:#1a1a1a;line-height:1.6;max-width:600px;margin:0 auto">
    <div style="background:#dc2626;color:#fff;padding:16px 20px;border-radius:8px 8px 0 0">
      <h2 style="margin:0;font-size:20px">\u{1F6A8} ${COMPANY} \u2014 Urgent Request Received</h2>
    </div>
    <div style="border:1px solid #e5e7eb;border-top:none;padding:20px;border-radius:0 0 8px 8px">
      <p>Hi there,</p>
      <p>We've received your <strong>urgent</strong> request and it has been escalated to our support lead immediately.</p>
      <p style="background:#fef2f2;border-left:4px solid #dc2626;padding:10px 14px;border-radius:4px"><strong>You can expect a response within 1 hour.</strong></p>
      <p><strong>Ticket Reference:</strong> ${ref}</p>
      <p>Warm regards,<br/><strong>${COMPANY} Support Team</strong></p>
    </div>
  </div>`;

  // ---- Billing-only reply (mirrors templates/email-billing.html) ----
  const billingReplyHtml = `
  <div style="font-family:Arial,sans-serif;color:#1a1a1a;line-height:1.6;max-width:600px;margin:0 auto">
    <div style="background:#2563eb;color:#fff;padding:16px 20px;border-radius:8px 8px 0 0">
      <h2 style="margin:0;font-size:20px">\u{1F4B3} ${COMPANY} \u2014 Billing Query Received</h2>
    </div>
    <div style="border:1px solid #e5e7eb;border-top:none;padding:20px;border-radius:0 0 8px 8px">
      <p>Hi there,</p>
      <p>Thank you for contacting us about your billing query. Your ticket has been created and routed to our billing team.</p>
      <p style="background:#eff6ff;border-left:4px solid #2563eb;padding:10px 14px;border-radius:4px">For faster assistance, contact <a href="mailto:billing@company.com" style="color:#2563eb">billing@company.com</a>.</p>
      <p><strong>Ticket Reference:</strong> ${ref}</p>
      <p>Warm regards,<br/><strong>${COMPANY} Billing Team</strong></p>
    </div>
  </div>`;

  // ---- General-only FAQ auto-reply (mirrors templates/email-general.html) ----
  const generalReplyHtml = `
  <div style="font-family:Arial,sans-serif;color:#1a1a1a;line-height:1.6">
    <h2 style="color:#16a34a;margin:0 0 8px">${COMPANY}</h2>
    <p>Hi there,</p>
    <p>Thanks for reaching out! While our team reviews your message, you may find a quick answer in our FAQ.</p>
    <p><a href="${FAQ_LINK}" style="color:#2563eb">Visit our FAQ &raquo;</a></p>
    <p style="background:#f0fdf4;padding:10px 14px;border-radius:6px"><strong>Ticket Reference:</strong> ${ref}</p>
    <p>Warm regards,<br/>${COMPANY}</p>
  </div>`;

  out.push({
    json: {
      ...j,
      company: COMPANY,
      confirmationHtml,
      urgentReplyHtml,
      billingReplyHtml,
      generalReplyHtml,
      logStatus: 'Routed',
      logNotes: `category=${j.category}; urgency=${j.urgency}; parse=${j.parseStatus || 'ok'}`
    }
  });
}

return out;
